// ─── HOOKS ───────────────────────────────────────────────────────────────────

function useInView(threshold = 0.1) {
  const ref = useRef(null);
  const [inView, setInView] = useState(false);
  useEffect(() => {
    const obs = new IntersectionObserver(
      ([entry]) => { if (entry.isIntersecting) setInView(true); },
      { threshold }
    );
    if (ref.current) obs.observe(ref.current);
    return () => obs.disconnect();
  }, [threshold]);
  return [ref, inView];
}

function useIsMobile() {
  const [mobile, setMobile] = useState(() => window.innerWidth < 768);
  useEffect(() => {
    const fn = () => setMobile(window.innerWidth < 768);
    window.addEventListener("resize", fn);
    return () => window.removeEventListener("resize", fn);
  }, []);
  return mobile;
}

// ─── SMALL COMPONENTS ────────────────────────────────────────────────────────

function Tag({ label }) {
  return (
    <span style={{
      fontSize: 11, padding: "3px 9px", borderRadius: 20,
      background: "#E6F1FB", color: "#185FA5", fontWeight: 500,
    }}>{label}</span>
  );
}

function SectionLabel({ children }) {
  return (
    <p style={{
      fontSize: 11, fontWeight: 600, letterSpacing: "1.2px",
      textTransform: "uppercase", color: "#888", marginBottom: 16,
    }}>{children}</p>
  );
}

function AnimatedBar({ pct, color, delay = 0 }) {
  const [width, setWidth] = useState(0);
  const [ref, inView] = useInView();
  useEffect(() => {
    if (inView) setTimeout(() => setWidth(pct), delay);
  }, [inView, pct, delay]);
  return (
    <div ref={ref} style={{ height: 3, background: "#f0f0f0", borderRadius: 2, overflow: "hidden" }}>
      <div style={{
        height: "100%", borderRadius: 2, background: color,
        width: `${width}%`, transition: "width 0.9s cubic-bezier(0.22,1,0.36,1)",
      }} />
    </div>
  );
}

// ─── NAVBAR ──────────────────────────────────────────────────────────────────

function Navbar({ active, setActive }) {
  const [scrolled, setScrolled] = useState(false);
  const [menuOpen, setMenuOpen] = useState(false);
  const isMobile = useIsMobile();

  useEffect(() => {
    const fn = () => setScrolled(window.scrollY > 20);
    window.addEventListener("scroll", fn);
    return () => window.removeEventListener("scroll", fn);
  }, []);

  useEffect(() => {
    if (!isMobile) setMenuOpen(false);
  }, [isMobile]);

  useEffect(() => {
    document.body.style.overflow = menuOpen ? "hidden" : "";
    return () => { document.body.style.overflow = ""; };
  }, [menuOpen]);

  const links = ["About", "Skills", "Experience", "Projects", "Contact"];

  const handleLinkClick = (l) => {
    setActive(l);
    setMenuOpen(false);
    setTimeout(() => {
      const el = document.getElementById(l.toLowerCase());
      if (el) el.scrollIntoView({ behavior: "smooth" });
    }, 10);
  };

  const Bar = ({ transform }) => (
    <span style={{
      display: "block", width: 22, height: 2,
      background: "#0F1117", borderRadius: 2,
      transform, transition: "transform 0.25s, opacity 0.2s",
    }} />
  );

  return (
    <nav style={{
      position: "fixed", top: 0, left: 0, right: 0, zIndex: 200,
      background: scrolled || menuOpen ? "rgba(255,255,255,0.97)" : "transparent",
      backdropFilter: scrolled || menuOpen ? "blur(12px)" : "none",
      borderBottom: scrolled || menuOpen ? "0.5px solid #e8e8e8" : "none",
      transition: "background 0.3s, border 0.3s",
    }}>
      {/* Top bar row */}
      <div style={{
        maxWidth: 1100, margin: "0 auto", padding: "0 1.25rem",
        display: "flex", alignItems: "center", justifyContent: "space-between",
        height: 60,
      }}>
        <div style={{
          fontFamily: "'Playfair Display', Georgia, serif",
          fontSize: 20, fontWeight: 700, letterSpacing: -0.5, color: "#0F1117",
        }}>
          Shibi<span style={{ color: "#378ADD" }}>.</span>
        </div>

        {/* Desktop links */}
        {!isMobile && (
          <div style={{ display: "flex", gap: 32 }}>
            {links.map(l => (
              <a key={l}
                href={`#${l.toLowerCase()}`}
                onClick={(e) => { e.preventDefault(); handleLinkClick(l); }}
                style={{
                  fontSize: 13, fontWeight: active === l ? 600 : 400,
                  color: active === l ? "#378ADD" : "#555",
                  textDecoration: "none", transition: "color 0.2s",
                }}
              >{l}</a>
            ))}
          </div>
        )}

        {/* Hamburger */}
        {isMobile && (
          <button
            onClick={() => setMenuOpen(o => !o)}
            style={{
              background: "none", border: "none", cursor: "pointer",
              padding: "8px", display: "flex", flexDirection: "column",
              gap: 5, alignItems: "center",
            }}
            aria-label="Toggle menu"
          >
            <Bar transform={menuOpen ? "translateY(7px) rotate(45deg)" : "none"} />
            <span style={{
              display: "block", width: 22, height: 2,
              background: "#0F1117", borderRadius: 2,
              opacity: menuOpen ? 0 : 1, transition: "opacity 0.2s",
            }} />
            <Bar transform={menuOpen ? "translateY(-7px) rotate(-45deg)" : "none"} />
          </button>
        )}
      </div>

      {/* Mobile slide-down menu */}
      {isMobile && (
        <div style={{
          maxHeight: menuOpen ? "400px" : "0px",
          overflow: "hidden",
          transition: "max-height 0.35s cubic-bezier(0.4,0,0.2,1)",
          background: "rgba(255,255,255,0.97)",
        }}>
          <div style={{ padding: "4px 1.25rem 20px", display: "flex", flexDirection: "column" }}>
            {links.map((l, idx) => (
              <a key={l}
                href={`#${l.toLowerCase()}`}
                onClick={(e) => { e.preventDefault(); handleLinkClick(l); }}
                style={{
                  fontSize: 16, fontWeight: active === l ? 600 : 400,
                  color: active === l ? "#378ADD" : "#222",
                  textDecoration: "none",
                  padding: "14px 0",
                  borderBottom: idx < links.length - 1 ? "0.5px solid #f0f0f0" : "none",
                  display: "flex", alignItems: "center", justifyContent: "space-between",
                }}
              >
                {l}
                {active === l && (
                  <span style={{
                    width: 6, height: 6, borderRadius: "50%",
                    background: "#378ADD", display: "inline-block",
                  }} />
                )}
              </a>
            ))}
          </div>
        </div>
      )}
    </nav>
  );
}

